function i(e,a,r){return r===a?1:1-(e-a)/(r-a)}function M(e){if(e.length===0)return{cheapest:null,fastest:null,bestValue:null,all:[]};let a=e.map(t=>t.price.total),r=e.map(t=>t.durationMinutes),s=e.map(t=>t.stops),u=Math.min(...a),l=Math.max(...a),c=Math.min(...r),p=Math.max(...r),m=Math.min(...s),d=Math.max(...s),o=e.map(t=>({flight:t,score:i(t.price.total,u,l)*.5+i(t.durationMinutes,c,p)*.3+i(t.stops,m,d)*.2}));o.sort((t,n)=>n.score-t.score);let h=e.reduce((t,n)=>n.price.total<t.price.total?n:t),g=e.reduce((t,n)=>n.durationMinutes<t.durationMinutes?n:t),b=o[0].flight;return{cheapest:h,fastest:g,bestValue:b,all:o.map(t=>t.flight)}}export{M as a};
